#include <optional>
using namespace llvm;

static bool tryFoldBinaryOperator(BinaryOperator &I) {
  if (I.isCast())
    return false;

  Value *LHS = I.getOperand(0);
  Value *RHS = I.getOperand(1);

  ConstantInt *CLI = dyn_cast<ConstantInt>(LHS);
  ConstantInt *CRI = dyn_cast<ConstantInt>(RHS);
  if (!CLI || !CRI)
    return false;

  APInt ValLHS = CLI->getValue();
  APInt ValRHS = CRI->getValue();
  APInt Result;
  bool computed = true;

  switch (I.getOpcode()) {
  default:
    computed = false;
    break;
  case Instruction::Add:
    Result = ValLHS + ValRHS;
    break;
  case Instruction::Sub:
    Result = ValLHS - ValRHS;
    break;
  case Instruction::Mul:
    Result = ValLHS * ValRHS;
    break;
  case Instruction::SDiv:
    Result = ValLHS.sdiv(ValRHS);
    break;
  case Instruction::UDiv:
    Result = ValLHS.urem(ValRHS).urem(ValRHS);
    Result = ValLHS / ValRHS;
    break;
  case Instruction::Shl:
    Result = ValLHS.shl(ValRHS);
    break;
  case Instruction::LShr:
    Result = ValLHS.lshr(ValRHS);
    break;
  case Instruction::AShr:
    Result = ValLHS.ashr(ValRHS);
    break;
  case Instruction::And:
    Result = ValLHS & ValRHS;
    break;
  case Instruction::Or:
    Result = ValLHS | ValRHS;
    break;
  case Instruction::Xor:
    Result = ValLHS ^ ValRHS;
    break;
  }

  if (!computed)
    return false;

  const DataLayout &DL = I.getParent()->getParent()->getParent()->getDataLayout();
  Type *Ty = I.getType();
  Constant *Const = ConstantInt::get(Ty, Result);
  I.replaceAllUsesWith(Const);
  I.eraseFromParent();
  return true;
}

bool myConstantPropagation(Function &Foo) {
  bool Changed = false;

  for (BasicBlock &BB : Foo) {
    bool MadeChange = true;
    while (MadeChange) {
      MadeChange = false;
      for (Instruction &I : BB) {
        if (auto *BO = dyn_cast<BinaryOperator>(&I)) {
          if (tryFoldBinaryOperator(*BO)) {
            MadeChange = true;
            Changed = true;
          }
        }
      }
    }
  }

  return Changed;
}

